mapper.select:
SELECT a.appeal_id AS appealId, a.appeal_employee_id AS appealEmployeeId, a.evaluation_period_id AS evaluationPeriodId, ep.eval_year AS evalYear, ep.eval_sequence AS evalSequence, e.employee_name AS employeeName, e.employee_code AS employeeCode, e.employee_tier AS employeeTier, d.department_name AS teamName, pd.department_name AS departmentName, a.appeal_type AS appealType, a.title, a.content, a.status, a.review_result AS reviewResult, qe1.score AS firstScore, qe2.score AS secondScore, ROUND(( COALESCE(qe1.score, 0) + COALESCE(qe2.score, 0) ) / NULLIF( (CASE WHEN qe1.score IS NOT NULL THEN 1 ELSE 0 END) + (CASE WHEN qe2.score IS NOT NULL THEN 1 ELSE 0 END), 0 ), 2) AS averageScore, a.filed_at AS filedAt, a.reviewed_at AS reviewedAt FROM evaluation_appeal a JOIN employee e ON e.employee_id = a.appeal_employee_id JOIN evaluation_period ep ON ep.eval_period_id = a.evaluation_period_id LEFT JOIN department d ON d.department_id = e.department_id LEFT JOIN department pd ON pd.department_id = d.parent_department_id LEFT JOIN qualitative_evaluation qe1 ON qe1.evaluatee_id = a.appeal_employee_id AND qe1.evaluation_period_id = a.evaluation_period_id AND qe1.evaluation_level = 1 LEFT JOIN qualitative_evaluation qe2 ON qe2.evaluatee_id = a.appeal_employee_id AND qe2.evaluation_period_id = a.evaluation_period_id AND qe2.evaluation_level = 2 LEFT JOIN qualitative_evaluation qe3 ON qe3.evaluatee_id = a.appeal_employee_id AND qe3.evaluation_period_id = a.evaluation_period_id AND qe3.evaluation_level = 3
AND a.status = #{status}
AND a.review_result != 'DISMISS' AND (qe3.status IS NULL OR qe3.status != 'CONFIRMED')
ORDER BY a.filed_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM evaluation_appeal a LEFT JOIN qualitative_evaluation qe3 ON qe3.evaluatee_id = a.appeal_employee_id AND qe3.evaluation_period_id = a.evaluation_period_id AND qe3.evaluation_level = 3
AND a.status = #{status}
AND a.review_result != 'DISMISS' AND (qe3.status IS NULL OR qe3.status != 'CONFIRMED')
